const body = $input.first().json.body || {};
const platform = body.platform || 'tiktok';
const aspect_ratio = body.aspect_ratio || '9:16';

const resolutions = {
  '9:16': { width: 1080, height: 1920 },
  '16:9': { width: 1920, height: 1080 },
  '1:1': { width: 1080, height: 1080 }
};

const res = resolutions[aspect_ratio] || resolutions['9:16'];
return [{ json: { ...body, platform, aspect_ratio, width: res.width, height: res.height } }];

const r = $input.first().json.choices?.[0]?.message?.content || '';
let d = {};
try { d = JSON.parse(r); } catch { const m = r.match(/\{[\s\S]*\}/); d = m ? JSON.parse(m[0]) : { scenes: [{ narration: r, seconds: 6 }] }; }
const b = $('Route by Platform').first().json;
return [{ json: { title: d.title, scenes: d.scenes, video_id: b.video_id, user_id: b.user_id, platform: b.platform, width: b.width, height: b.height } }];

const item = items[0].json;
const voice = 'nb-NO-PernilleNeural';
return [{ json: { ...item, tts_voice: voice } }];

const { execSync } = require('child_process');
const item = items[0].json;
const text = (item.scenes || []).map(s => s.narration || '').filter(Boolean).join('. ').substring(0, 2000);
const v = item.video_id;
const dir = `/workspace/video_assets/${v}`;
try {
  execSync(`mkdir -p ${dir}`, { shell: '/bin/bash' });
  execSync(`edge-tts --voice "${item.tts_voice}" --text "${text}" --write-media "${dir}/voice.mp3"`, { encoding: 'utf-8', timeout: 300000, shell: '/bin/bash' });
  return [{ json: { ...item, voice_path: `${dir}/voice.mp3` } }];
} catch(e) { throw new Error('Voice: ' + e.message); }

const item = items[0].json;
const scenes = item.scenes || [];
return scenes.map((s, i) => ({ json: { video_id: item.video_id, query: s.search_keywords?.[0] || item.title, duration: s.seconds || 6, width: item.width, height: item.height, index: i } }));

const hits = $input.first().json.hits || [];
if (!hits.length) return [{ json: { url: null } }];
const url = hits[0]?.videos?.large?.url || hits[0]?.videos?.medium?.url || hits[0]?.videos?.small?.url;
return [{ json: { url, id: hits[0].id } }];

const { execSync } = require('child_process');
const i = items[0].json;
const dir = `/workspace/video_assets/${i.video_id}/clips`;
const sz = `${i.width}x${i.height}`;
execSync(`mkdir -p ${dir}`, { shell: '/bin/bash' });

if (!i.url) {
  execSync(`ffmpeg -y -f lavfi -i color=c=black:s=${sz}:r=30 -t ${i.duration} -c:v libx264 -preset fast ${dir}/s_${i.index}.mp4`, { encoding: 'utf-8', timeout: 120000, shell: '/bin/bash' });
  return [{ json: { path: `${dir}/s_${i.index}.mp4`, fallback: true } }];
}

try {
  execSync(`ffmpeg -y -i "${i.url}" -t ${i.duration} -vf scale=${sz}:force_original_aspect_ratio=decrease,pad=${sz}:(ow-iw)/2:(oh-ih)/2,setsar=1 -c:v libx264 -preset fast -an ${dir}/s_${i.index}.mp4`, { encoding: 'utf-8', timeout: 300000, shell: '/bin/bash' });
  return [{ json: { path: `${dir}/s_${i.index}.mp4` } }];
} catch {
  execSync(`ffmpeg -y -f lavfi -i color=c=black:s=${sz}:r=30 -t ${i.duration} -c:v libx264 -preset fast ${dir}/s_${i.index}.mp4`, { encoding: 'utf-8', timeout: 120000, shell: '/bin/bash' });
  return [{ json: { path: `${dir}/s_${i.index}.mp4`, fallback: true } }];
}

const { execSync } = require('child_process');
const i = items[0].json;
const dir = `/workspace/video_assets/${i.video_id}/clips`;
const files = execSync(`ls ${dir}/s_*.mp4 2>/dev/null | sort -V`, { encoding: 'utf-8', shell: '/bin/bash' }).trim();
if (!files) throw new Error('Ingen scener');
execSync(`echo "$files" | sed "s/^/file '/;s/$/'/" > ${dir}/list.txt && ffmpeg -y -f concat -safe 0 -i ${dir}/list.txt -c:v libx264 -preset fast -c:a aac ${dir}/concat.mp4`, { encoding: 'utf-8', timeout: 300000, shell: '/bin/bash' });
return [{ json: { concat: `${dir}/concat.mp4` } }];

const { execSync } = require('child_process');
const i = items[0].json;
const v = i.video_id;
const u = i.user_id;
const dir = `/workspace/video_assets/${v}`;
const supabase = $env.SUPABASE_URL;
const key = $env.SUPABASE_SERVICE_ROLE_KEY;

try {
  execSync(`ffmpeg -y -i "${dir}/concat.mp4" -i "${dir}/voice.mp3" -c:v copy -c:a aac -shortest "${dir}/final.mp4"`, { encoding: 'utf-8', timeout: 300000, shell: '/bin/bash' });
} catch {
  execSync(`cp "${dir}/concat.mp4" "${dir}/final.mp4"`);
}

const path = `${u}/${v}/final.mp4`;
try {
  execSync(`curl -sf -X POST "${supabase}/storage/v1/object/videos/${path}" -H "Authorization: Bearer ${key}" -H "Content-Type: video/mp4" --data-binary @"${dir}/final.mp4"`, { encoding: 'utf-8', timeout: 600000, shell: '/bin/bash' });
} catch(e) { throw new Error('Upload: ' + e.message); }
return [{ json: { url: `${supabase}/storage/v1/object/public/videos/${path}` } }];
